import {
  getCourses,
  deleteCourse,
  exportCourses,
  getUnassignedStudents,
  assignStudentsToCourse,
  getCourseStats,
  importCourses,
  getCourseImportTemplate,
} from '@/src/services/courseService';
import AddCourseModal from '@/src/components/courses/AddCourseModal';
import StudentDetailDrawer from '@/src/components/students/StudentDetailDrawer';
import CourseStudentsDrawer from '@/src/components/courses/CourseStudentsDrawer';
import ConfirmModal from '@/src/components/shared/ConfirmModal';
import UnderDevelopment from '@/src/components/shared/UnderDevelopment';
import ViDateInput from '@/src/components/shared/ViDateInput';
import { useAuth } from '@/src/context/AuthContext';

export default function CoursesPage() {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState<'danh-sach' | 'chua-vao'>('danh-sach');

  // Courses State
  const [courses, setCourses] = useState<any[]>([]);
  const [meta, setMeta] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [courseStats, setCourseStats] = useState<any>(null);

  // Unassigned Students State
  const [unassignedList, setUnassignedList] = useState<any[]>([]);
  const [unassignedMeta, setUnassignedMeta] = useState<any>(null);
  const [isUnassignedLoading, setIsUnassignedLoading] = useState(false);
  const [unassignedSearch, setUnassignedSearch] = useState('');
  const [unassignedRank, setUnassignedRank] = useState('Mọi hạng');
  const [debouncedUnassignedSearch, setDebouncedUnassignedSearch] = useState('');

  // Common UI State
  const [searchTerm, setSearchTerm] = useState('');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');
  const [statusFilter, setStatusFilter] = useState('Tất cả');
  const [debouncedSearch, setDebouncedSearch] = useState('');

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [courseToEdit, setCourseToEdit] = useState<any>(null);
  const [courseToDelete, setCourseToDelete] = useState<any>(null);
  const [selectedStudents, setSelectedStudents] = useState<string[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [targetCourse, setTargetCourse] = useState('');
  const [isAssigning, setIsAssigning] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [isUtilsMenuOpen, setIsUtilsMenuOpen] = useState(false);
  const fileInputRef = React.useRef<HTMLInputElement>(null);

  // Course Student List Drawer State
  const [selectedCourseForList, setSelectedCourseForList] = useState<string | null>(null);
  const [selectedCourseName, setSelectedCourseName] = useState('');
  const [selectedCourseEndDate, setSelectedCourseEndDate] = useState<string | null>(null);

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      setSelectedStudents(unassignedList.map((s) => s._id));
    } else {
      setSelectedStudents([]);
    }
  };

  const handleSelectStudent = (id: string) => {
    if (selectedStudents.includes(id)) {
      setSelectedStudents(selectedStudents.filter((sId) => sId !== id));
    } else {
      setSelectedStudents([...selectedStudents, id]);
    }
  };

  const handleAssign = async (studentId?: string) => {
    if (!targetCourse || targetCourse === '— Chọn khóa —') {
      toast.warning('Vui lòng chọn khóa đích trước!');
      return;
    }

    const idsToAssign = studentId ? [studentId] : selectedStudents;

    if (idsToAssign.length === 0) {
      toast.warning('Vui lòng chọn ít nhất một học viên!');
      return;
    }

    // Check max students limit
    const targetCourseData = courses.find((c) => c._id === targetCourse);
    if (targetCourseData) {
      const max = targetCourseData.max_students || 50;
      const current = targetCourseData.student_count || 0;
      if (current + idsToAssign.length > max) {
        toast.error(`Khóa học chỉ còn nhận ${max - current} học viên nữa (tối đa ${max}). Không thể gán thêm.`);
        return;
      }
    }

    setIsAssigning(true);
    try {
      await assignStudentsToCourse(targetCourse, idsToAssign);
      toast.success(`Đã gán thành công ${idsToAssign.length} học viên`);

      // Refresh both lists
      fetchCourses();
      fetchUnassignedStudents();

      // Reset selection
      if (!studentId) setSelectedStudents([]);
      else setSelectedStudents((prev) => prev.filter((id) => id !== studentId));
    } catch (error: any) {
      toast.error(error.message || 'Lỗi khi gán học viên');
    } finally {
      setIsAssigning(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'Đã KSK':
        return 'bg-emerald-50 text-emerald-600 border-emerald-200';
      case 'Đã đậu':
        return 'bg-teal-50 text-teal-600 border-teal-200';
      case 'Đang học':
      case 'Đã nộp hồ sơ':
      case 'Nộp hồ sơ':
        return 'bg-sky-50 text-sky-600 border-sky-200';
      case 'Đang thi':
        return 'bg-purple-50 text-purple-600 border-purple-200';
      case 'Thi lại':
        return 'bg-rose-50 text-rose-600 border-rose-200';
      default:
        return 'bg-gray-50 text-gray-600 border-gray-200';
    }
  };

  const fetchCourses = async (page = 1, limit = 10) => {
    setIsLoading(true);
    try {
      const filters = {
        name: debouncedSearch,
        start_date_from: fromDate,
        start_date_to: toDate,
        status: statusFilter !== 'Tất cả' ? statusFilter : undefined,
      };

      const [res, statsRes] = await Promise.all([getCourses(page, limit, filters), getCourseStats()]);

      if (res.success && res.data && res.data.data) {
        setCourses(res.data.data);
        setMeta(res.data.meta);
      }

      if (statsRes.success && statsRes.data) {
        setCourseStats(statsRes.data);
      }
    } catch (error) {
      console.error('Error fetching courses:', error);
      toast.error('Lỗi khi tải danh sách khóa học');
    } finally {
      setIsLoading(false);
    }
  };

  const fetchUnassignedStudents = async (page = 1, limit = 100) => {
    setIsUnassignedLoading(true);
    try {
      const params = {
        search: debouncedUnassignedSearch,
        license_category_id: unassignedRank !== 'Mọi hạng' ? unassignedRank : undefined,
      };
      const res = await getUnassignedStudents(params);
      if (res.success && res.data && res.data.data) {
        setUnassignedList(res.data.data);
        setUnassignedMeta(res.data.meta);
      }
    } catch (error) {
      toast.error('Lỗi khi tải danh sách học viên');
    } finally {
      setIsUnassignedLoading(false);
    }
  };

  const handleExport = async () => {
    setIsExporting(true);
    setIsUtilsMenuOpen(false);
    try {
      const filters = {
        name: searchTerm,
        start_date_from: fromDate,
        start_date_to: toDate,
        status: statusFilter !== 'Tất cả' ? statusFilter : undefined,
      };
      await exportCourses(filters);
      toast.success('Xuất dữ liệu Excel thành công');
    } catch (error) {
      toast.error('Lỗi khi xuất dữ liệu');
    } finally {
      setIsExporting(false);
    }
  };

  const handleDownloadTemplate = async () => {
    setIsUtilsMenuOpen(false);
    try {
      await getCourseImportTemplate();
      toast.success('Đang tải file mẫu...');
    } catch (error) {
      toast.error('Lỗi khi tải file mẫu');
    }
  };

  const handleImportExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setIsUtilsMenuOpen(false);
    try {
      await importCourses(file);
      toast.success('Đã bắt đầu nhập dữ liệu. Vui lòng theo dõi thông báo để biết kết quả.');
      // Reset input
      if (fileInputRef.current) fileInputRef.current.value = '';
    } catch (error: any) {
      toast.error(error.message || 'Lỗi khi nhập dữ liệu');
    } finally {
      setIsImporting(false);
    }
  };

  const executeDeleteCourse = async () => {
    if (!courseToDelete) return;
    try {
      const res = await deleteCourse(courseToDelete._id);
      if (res.success) {
        toast.success('Đã xóa khóa học thành công!');
        fetchCourses();
      } else {
        toast.error(res.message || 'Lỗi khi xóa khóa học');
      }
    } catch (error) {
      toast.error('Lỗi kết nối khi xóa khóa học');
    } finally {
      setCourseToDelete(null);
    }
  };

  // Debounce search term
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchTerm.trim());
    }, 500);
    return () => clearTimeout(timer);
  }, [searchTerm]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedUnassignedSearch(unassignedSearch.trim());
    }, 500);
    return () => clearTimeout(timer);
  }, [unassignedSearch]);

  useEffect(() => {
    fetchCourses();
  }, [debouncedSearch, fromDate, toDate, statusFilter]);

  useEffect(() => {
    if (activeTab === 'chua-vao') {
      fetchUnassignedStudents();
    }
  }, [debouncedUnassignedSearch, unassignedRank, activeTab]);

  useEffect(() => {
    const handleRefresh = () => {
      fetchCourses();
      fetchUnassignedStudents();
    };
    window.addEventListener('refresh-course-list', handleRefresh);
    return () => window.removeEventListener('refresh-course-list', handleRefresh);
  }, []);

  const stats = [
    {
      label: 'Tổng khóa',
      value: (courseStats?.total || 0).toString(),
      icon: Layers,
      color: 'text-indigo-600',
      bgColor: 'bg-indigo-50',
    },
    {
      label: 'Nhập / Sắp KG',
      value: (courseStats?.draft || 0).toString(),
      icon: Clock,
      color: 'text-amber-500',
      bgColor: 'bg-amber-50',
    },
    {
      label: 'Đang học',
      value: (courseStats?.ongoing || 0).toString(),
      icon: GraduationCap,
      color: 'text-emerald-500',
      bgColor: 'bg-emerald-50',
    },
    {
      label: 'Đã kết thúc',
      value: (courseStats?.completed || 0).toString(),
      icon: CheckSquare,
      color: 'text-gray-500',
      bgColor: 'bg-gray-50',
    },
  ];

  return (
