        isOpen={!!selectedCourseForList}
        onClose={() => setSelectedCourseForList(null)}
        courseId={selectedCourseForList || ''}
        courseName={selectedCourseName}
        courseEndDate={selectedCourseEndDate}
      />

      <ConfirmModal
        isOpen={!!courseToDelete}
        onClose={() => setCourseToDelete(null)}
        onConfirm={executeDeleteCourse}
        title="Xác nhận xóa khóa học"
        message={`Bạn có chắc chắn muốn xóa khóa học "${courseToDelete?.name}" không? Hành động này không thể hoàn tác và mọi dữ liệu liên quan sẽ bị mất.`}
        type="danger"
        confirmText="Xác nhận xóa"
      />
    </div>
  );
}

'use client';

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import dynamic from 'next/dynamic';
import { toast } from 'sonner';
import { Plus, Download, Upload, Trash2 } from 'lucide-react';
import {
  getStudents,
  getCities,
  getLicenseCategories,
  exportStudents,
  deleteStudent,
  bulkDeleteStudents,
  updateStudent,
  getImportStats,
} from '@/src/services/studentService';
import { getCourses } from '@/src/services/courseService';

// --- MODULAR COMPONENTS (Internal) ---
import StudentFilters from '@/src/components/students/modules/StudentFilters';
import StudentStatsBar from '@/src/components/students/modules/StudentStatsBar';

// Maps UI status labels (shown in filter tabs) → BE status_detail values.
// BE entity type: 'Chờ KSK' | 'Đã KSK' | 'Đã nộp HS' | 'Đang học' | 'Đang thi' | 'Đã đậu' | 'Thi lại' | 'Nghỉ học' | 'Trượt'
const UI_LABEL_TO_BE_STATUS: Record<string, string> = {
  'Nộp HS': 'Đã nộp HS',
  'Đã đậu': 'Đã đậu',
  // Management statuses are handled explicitly in BE using these labels as keys
};

function toBeStatus(uiLabel: string): string {
  return UI_LABEL_TO_BE_STATUS[uiLabel] ?? uiLabel;
}
import StudentTable from '@/src/components/students/modules/StudentTable';

// --- DYNAMIC IMPORTS (Performance Optimization) ---
const StudentDetailDrawer = dynamic(() => import('@/src/components/students/StudentDetailDrawer'), {
  ssr: false,
  loading: () => <div className="fixed inset-0 bg-black/20 animate-pulse z-[100]" />,
});

const AddStudentModal = dynamic(() => import('@/src/components/students/AddStudentModal'), {
  ssr: false,
});

const ImportStudentModal = dynamic(() => import('@/src/components/students/ImportStudentModal'), {
  ssr: false,
});

const ConfirmModal = dynamic(() => import('@/src/components/shared/ConfirmModal'), {
  ssr: false,
});

const UnderDevelopment = dynamic(() => import('@/src/components/shared/UnderDevelopment'), {
  ssr: false,
});

export default function StudentsPage() {
  // --- FILTER STATE ---
  const [searchTerm, setSearchTerm] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('Tất cả');
  const [vehicleFilter, setVehicleFilter] = useState('Tất cả');
  const [selectedRank, setSelectedRank] = useState('Tất cả');
  const [selectedRegion, setSelectedRegion] = useState('Tất cả');
  const [selectedCourse, setSelectedCourse] = useState('Tất cả');
  const [debtFilter, setDebtFilter] = useState('Tất cả');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');

  // --- UI STATE ---
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);
  const [deleteConfirmStudent, setDeleteConfirmStudent] = useState<any>(null);
  const [isBulkDeleteConfirmOpen, setIsBulkDeleteConfirmOpen] = useState(false);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [isExporting, setIsExporting] = useState(false);
  const latestRequestIdRef = useRef(0);

  // --- DATA STATE ---
  const [students, setStudents] = useState<any[]>([]);
  const [meta, setMeta] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [cities, setCities] = useState<any[]>([]);
  const [courses, setCourses] = useState<any[]>([]);
  const [licenseCategories, setLicenseCategories] = useState<any[]>([]);

  // --- MANAGEMENT STATS STATE ---
  const [managementStats, setManagementStats] = useState<any>(null);
  const [isStatsLoading, setIsStatsLoading] = useState(false);

  const fetchManagementStats = useCallback(async () => {
    setIsStatsLoading(true);
    try {
      const res = await getImportStats();
      if (res.success) {
        setManagementStats(res.data);
      }
    } catch (err) {
      console.error('Failed to fetch management stats', err);
    } finally {
      setIsStatsLoading(false);
    }
  }, []);

  // 1. Initial Load: Filters & Stats
  useEffect(() => {
    const loadFilterData = async () => {
      try {
        const [citiesRes, coursesRes, categoriesRes] = await Promise.all([
          getCities(),
          getCourses(1, 100),
          getLicenseCategories(),
        ]);

        if (citiesRes.success) setCities(citiesRes.data || []);
        if (coursesRes.success) {
          const courseData = coursesRes.data;
          setCourses(Array.isArray(courseData) ? courseData : courseData?.data || []);
        }
        if (categoriesRes.success) setLicenseCategories(categoriesRes.data || []);
      } catch (err) {
        console.error('Failed to load filter data', err);
      }
    };
    loadFilterData();
    fetchManagementStats();
  }, [fetchManagementStats]);

  // 2. Debounced Search Sync
  useEffect(() => {
    const timer = setTimeout(() => setDebouncedSearch(searchTerm.trim()), 500);
    return () => clearTimeout(timer);
  }, [searchTerm]);

  // 3. Data Fetching
  const fetchStudents = useCallback(
    async (page = 1, limit = 10) => {
      const requestId = ++latestRequestIdRef.current;
      setIsLoading(true);

      try {
        const filters = {
          search: debouncedSearch,
          status: toBeStatus(statusFilter),
          vehicle_type: vehicleFilter,
          license_category_id: selectedRank,
          region_id: selectedRegion,
          course_id: selectedCourse,
          from_date: fromDate,
          to_date: toDate,
          debt_status: debtFilter === 'Tất cả' ? null : debtFilter,
          simple: true,
        };

        const res = await getStudents(page, limit, filters);
        if (requestId !== latestRequestIdRef.current) return;

        if (res.success && res.data) {
          setStudents(res.data.data || []);
          setMeta(res.data.meta);
        }
      } catch {
        if (requestId === latestRequestIdRef.current) {
          toast.error('Lỗi khi tải danh sách học viên');
        }
      } finally {
        if (requestId === latestRequestIdRef.current) {
          setIsLoading(false);
        }
      }
    },
    [
      debouncedSearch,
      statusFilter,
      vehicleFilter,
      selectedRank,
      selectedRegion,
      selectedCourse,
      fromDate,
      toDate,
      debtFilter,
    ],
  );

  useEffect(() => {
    fetchStudents(1, 10);
    setSelectedIds([]); // Reset selection on filter change
  }, [fetchStudents]);

  // 4. Real-time Refresh Listener
  useEffect(() => {
    const handleRefresh = () => {
      fetchStudents(1, 10);
      fetchManagementStats();
    };
    window.addEventListener('refresh-student-list', handleRefresh);
    return () => window.removeEventListener('refresh-student-list', handleRefresh);
  }, [fetchStudents, fetchManagementStats]);

  // 5. Data Mapping (Memoized for performance)
  const mappedStudents = useMemo(() => {
    return students.map((item: any) => ({
      id: item._id,
      student_id: item.student_id || `HV${item._id.slice(-4).toUpperCase()}`,
      name:
        item.fullName ||
        (item.user_id?.last_name ? `${item.user_id.last_name} ${item.user_id.first_name || ''}` : 'Không rõ'),
      phone: item.user_id?.phone || item.phone || '--',
      email: item.user_id?.email || '--',
      rank: item.license_category_name || item.license_category_id || 'B2',
      region: item.region_id?.name || 'Nội thành',
      status: item.status_detail || item.status || 'Chờ KSK',
      tuition: item.tuition || { total: 0, paid: 0 },
      progress: (() => {
        const isP1Done = item.status_detail === 'Đã KSK' || item.health_check?.status === 'Đủ điều kiện';
        const isP2Done = !!item.progress_flags?.cabin_completed;
        const isP3Done = item.status === 'finished' || item.status === 'Đã đậu';
        return {
          p1: isP1Done ? 'done' : 'pending',
          p2: isP2Done ? 'done' : isP1Done ? 'pending' : 'waiting',
          p3: isP3Done ? 'done' : isP2Done ? 'pending' : 'waiting',
        };
      })(),
    }));
  }, [students]);

  // 5. Shared Actions
  const handleStatusTransition = async (student: any) => {
    const STATUS_SEQUENCE = [
      'Đã nộp HS',
      'Chờ KSK',
      'Đã KSK',
      'Chờ xếp khóa',
      'Đã vào khóa',
      'Đang học',
      'Đang thi',
      'Đã đậu',
      'Thi lại',
    ];

    const currentStatus = student.status;
    const currentIndex = STATUS_SEQUENCE.indexOf(currentStatus);

    if (currentIndex === -1 || currentIndex === STATUS_SEQUENCE.length - 1) {
      toast.error(`Không thể chuyển tiếp trạng thái từ "${currentStatus}" hoặc đã ở trạng thái cuối cùng.`);
      return;
    }

    const nextStatus = STATUS_SEQUENCE[currentIndex + 1];

    try {
      toast.loading(`Đang chuyển trạng thái học viên ${student.name} sang "${nextStatus}"...`, {
        id: 'status-transition',
      });

      const res = await updateStudent(student.id, { status: nextStatus });

      if (res.success || res.status === 200 || !res.error) {
        toast.success(`Đã chuyển trạng thái học viên ${student.name} sang "${nextStatus}" thành công!`, {
          id: 'status-transition',
        });
        fetchStudents(meta?.page || 1, 10);
      } else {
        toast.error(res.message || 'Lỗi khi cập nhật trạng thái', { id: 'status-transition' });
      }
    } catch (error: any) {
      console.error('Status transition error:', error);
      toast.error(error.message || 'Lỗi kết nối khi cập nhật trạng thái', { id: 'status-transition' });
    }
  };

  const handleExport = async () => {
    setIsExporting(true);
    try {
      const filters = {
        search: debouncedSearch,
        status: toBeStatus(statusFilter),
        vehicle_type: vehicleFilter,
        license_category_id: selectedRank,
        region_id: selectedRegion,
        course_id: selectedCourse,
        from_date: fromDate,
        to_date: toDate,
      };
      await exportStudents(filters);
      toast.success('Xuất dữ liệu Excel thành công');
    } catch (error: any) {
      toast.error(error.message || 'Lỗi khi xuất dữ liệu');
    } finally {
      setIsExporting(false);
    }
  };

  const handleDeleteConfirm = async () => {
    if (!deleteConfirmStudent) return;
    const studentId = deleteConfirmStudent.id;
    const studentName = deleteConfirmStudent.name;

    try {
      toast.loading(`Đang xóa học viên ${studentName}...`, { id: 'delete-student' });

      // Immediate UI update for better UX
      setStudents((prev) => prev.filter((s) => s._id !== studentId));

      const res = await deleteStudent(studentId);
      if (res.success || res.status === 200 || !res.error) {
        toast.success(`Đã xóa vĩnh viễn hồ sơ: ${studentName}`, { id: 'delete-student' });
        setDeleteConfirmStudent(null);
        // We still fetch to ensure meta/stats are updated, but the UI is already clean
        fetchStudents(meta?.page || 1, 10);
        fetchManagementStats();
      } else {
        // Rollback on failure
        fetchStudents(meta?.page || 1, 10);
        toast.error(res.message || 'Lỗi khi xóa học viên', { id: 'delete-student' });
      }
    } catch (error: any) {
      fetchStudents(meta?.page || 1, 10);
      toast.error(error.message || 'Lỗi kết nối khi xóa học viên', { id: 'delete-student' });
    }
  };

  const handleBulkDeleteConfirm = async () => {
    if (selectedIds.length === 0) return;

    try {
      toast.loading(`Đang xóa ${selectedIds.length} học viên đã chọn...`, { id: 'bulk-delete' });

      // Immediate UI update
      setStudents((prev) => prev.filter((s) => !selectedIds.includes(s._id)));

      const res = await bulkDeleteStudents(selectedIds);
      if (res.success || res.status === 200 || !res.error) {
        toast.success(`Đã xóa thành công ${selectedIds.length} học viên`, { id: 'bulk-delete' });
        setSelectedIds([]);
        setIsBulkDeleteConfirmOpen(false);
        fetchStudents(1, 10);
        fetchManagementStats();
      } else {
        fetchStudents(1, 10);
        toast.error(res.message || 'Lỗi khi xóa hàng loạt', { id: 'bulk-delete' });
      }
    } catch (error: any) {
      fetchStudents(1, 10);
      toast.error(error.message || 'Lỗi kết nối khi xóa hàng loạt', { id: 'bulk-delete' });
    }
  };

  return (
    <div className="flex flex-col gap-6 animate-in fade-in duration-700">
      {/* 1. Header Row */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl sm:text-3xl font-extrabold text-gray-900 tracking-tight">Quản lý Học viên</h1>
          <p className="text-gray-500 font-medium mt-1">Quản lý hồ sơ, theo dõi tiến độ thi và học phí</p>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button
            onClick={handleExport}
            disabled={isExporting}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-700 font-bold rounded-xl hover:bg-gray-50 transition-all shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isExporting ? (
              <div className="w-4 h-4 border-2 border-indigo-600/20 border-t-indigo-600 rounded-full animate-spin" />
            ) : (
              <Download className="w-4 h-4" />
            )}
            <span className="hidden sm:inline">{isExporting ? 'Đang xuất...' : 'Xuất dữ liệu'}</span>
          </button>
          <button
            onClick={() => setIsImportModalOpen(true)}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-white border border-gray-200 text-gray-700 font-bold rounded-xl hover:bg-gray-50 transition-all shadow-sm"
          >
            <Upload className="w-4 h-4" />
            <span className="hidden sm:inline">Nhập tệp (Excel)</span>
          </button>
          <button
            onClick={() => setIsAddModalOpen(true)}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white font-bold rounded-xl shadow-lg shadow-indigo-600/25 hover:bg-indigo-700 transition-all active:scale-95 flex-1 sm:flex-none"
          >
            <Plus className="w-4 h-4" />
            Thêm học viên
          </button>
        </div>
      </div>

      {/* 2. Management Summary Stats */}
      <StudentStatsBar stats={managementStats} isLoading={isStatsLoading} onRefresh={fetchManagementStats} />

      {/* 3. Modular Filter System */}
      <StudentFilters
        searchTerm={searchTerm}
        setSearchTerm={setSearchTerm}
        statusFilter={statusFilter}
        setStatusFilter={setStatusFilter}
        vehicleFilter={vehicleFilter}
        setVehicleFilter={setVehicleFilter}
        selectedRank={selectedRank}
        setSelectedRank={setSelectedRank}
        selectedRegion={selectedRegion}
        setSelectedRegion={setSelectedRegion}
        selectedCourse={selectedCourse}
        setSelectedCourse={setSelectedCourse}
        debtFilter={debtFilter}
        setDebtFilter={setDebtFilter}
        fromDate={fromDate}
        setFromDate={setFromDate}
        toDate={toDate}
        setToDate={setToDate}
        meta={meta}
        cities={cities}
        courses={courses}
        licenseCategories={licenseCategories}
        isLoading={isLoading}
      />

      {/* 3. Logical Summary & Bulk Actions */}
      <div className="flex justify-between items-center -mt-2 ml-1">
        <div className="text-xs font-bold text-indigo-600">
          {meta ? `${meta.total} học viên tìm thấy` : 'Đang tải kết quả...'}
        </div>

        {selectedIds.length > 0 && (
          <div className="flex items-center gap-3 animate-in slide-in-from-right-4">
            <span className="text-xs font-bold text-gray-500">Đã chọn {selectedIds.length} học viên</span>
            <button
              onClick={() => setIsBulkDeleteConfirmOpen(true)}
              className="px-3 py-1 bg-rose-50 text-rose-600 text-xs font-bold rounded-lg border border-rose-100 hover:bg-rose-100 transition-colors flex items-center gap-1.5"
            >
              <Trash2 className="w-3.5 h-3.5" />
              Xóa đã chọn
            </button>
            <button onClick={() => setSelectedIds([])} className="text-xs font-bold text-gray-400 hover:text-gray-600">
              Hủy
            </button>
          </div>
        )}
      </div>

      {/* 4. Modular Table System */}
      <StudentTable
        students={mappedStudents}
        meta={meta}
        isLoading={isLoading}
        onFetchData={(p) => fetchStudents(p)}
        onSelectStudent={setSelectedStudent}
        onStatusTransition={handleStatusTransition}
        onDeleteStudent={setDeleteConfirmStudent}
        onRetireStudent={() => {}}
        selectedIds={selectedIds}
        onSelectionChange={setSelectedIds}
      />

      {/* 5. Lazy Loaded Modals */}
      {isAddModalOpen && <AddStudentModal isOpen={isAddModalOpen} onClose={() => setIsAddModalOpen(false)} />}

      <ImportStudentModal
        isOpen={isImportModalOpen}
        onClose={() => setIsImportModalOpen(false)}
        onSuccess={() => {
          fetchStudents(1, 10);
          fetchManagementStats();
        }}
      />

      {selectedStudent && (
        <StudentDetailDrawer
          isOpen={!!selectedStudent}
          onClose={() => setSelectedStudent(null)}
          student={selectedStudent}
          onRefresh={() => fetchStudents(meta?.page || 1, 10)}
        />
      )}

      {deleteConfirmStudent && (
        <ConfirmModal
          isOpen={!!deleteConfirmStudent}
          onClose={() => setDeleteConfirmStudent(null)}
          onConfirm={handleDeleteConfirm}
          title="Xóa học viên"
          message={`Xác nhận xóa vĩnh viễn hồ sơ của ${deleteConfirmStudent?.name}?`}
          confirmText="Xóa vĩnh viễn"
          type="danger"
        />
      )}

      {isBulkDeleteConfirmOpen && (
        <ConfirmModal
          isOpen={isBulkDeleteConfirmOpen}
          onClose={() => setIsBulkDeleteConfirmOpen(false)}
          onConfirm={handleBulkDeleteConfirm}
          title="Xóa hàng loạt"
          message={`Bạn có chắc chắn muốn xóa vĩnh viễn ${selectedIds.length} học viên đã chọn? Hành động này không thể hoàn tác.`}
          confirmText={`Xóa ${selectedIds.length} học viên`}
          type="danger"
        />
      )}
    </div>
  );
}

