interface SidebarProps {
  isCollapsed?: boolean;
  onToggleCollapse?: () => void;
  showCollapseToggle?: boolean;
}

const Sidebar = ({
  isCollapsed = false,
  onToggleCollapse,
  showCollapseToggle = true,
}: SidebarProps) => {
  const pathname = usePathname();
  const router = useRouter();
  const { setToken, user } = useAuth();
  const shouldReduceMotion = useReducedMotion();
  const isSettingsSection = pathname.startsWith('/settings');
  const [settingsOpen, setSettingsOpen] = useState(isSettingsSection && !isCollapsed);
  const [isSettingsHovered, setIsSettingsHovered] = useState(false);
  const [isLogoutConfirmOpen, setIsLogoutConfirmOpen] = useState(false);
  const settingsBtnRef = useRef<HTMLDivElement>(null);
  const [popupRect, setPopupRect] = useState<{ top: number; left: number } | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Ensure we're client-side for portal
  useEffect(() => { setIsMounted(true); }, []);

  // Sync settings menu state when collapsing
  React.useEffect(() => {
    if (isCollapsed) setSettingsOpen(false);
    else if (isSettingsSection) setSettingsOpen(true);
  }, [isCollapsed, isSettingsSection]);

  // Close popup when sidebar expands
  useEffect(() => {
    if (!isCollapsed) setIsSettingsHovered(false);
  }, [isCollapsed]);


  const NavItem = ({ item }: { item: any }) => {
    const isActive = pathname === item.href || (item.href === '/dashboard' && pathname === '/');
    const Icon = item.icon;
    return (
      <li className="relative group/item">
        <Link
          href={item.href}
          className={`gpu-smooth motion-safe-transition flex items-center gap-3 px-4 py-2.5 rounded-xl group ${
            isActive
              ? 'bg-indigo-600/5 text-indigo-700 shadow-sm border border-indigo-100/50'
              : 'text-gray-500 hover:bg-gray-50 hover:text-gray-900 border border-transparent'
          } ${isCollapsed ? 'justify-center px-0 w-12 h-12 mx-auto' : ''}`}
        >
          <Icon className={`w-5 h-5 shrink-0 motion-safe-transition ${isActive ? 'text-indigo-600 scale-105' : 'text-gray-400 group-hover:text-gray-700 group-hover:scale-105'}`} />
          {!isCollapsed && (
             <>
               <span className={`text-sm tracking-tight ${isActive ? 'font-bold' : 'font-semibold'}`}>{item.label}</span>
               {isActive && <div className="ml-auto w-1.5 h-1.5 rounded-full bg-indigo-600 shadow-glow shadow-indigo-600/50 animate-pulse" />}
             </>
          )}
        </Link>

        {/* Tooltip for collapsed mode - Premium Glassmorphism */}
        {isCollapsed && (
          <div className="absolute left-full ml-4 px-3 py-1.5 bg-gray-900/90 backdrop-blur-md text-white text-[10px] font-black rounded-xl opacity-0 invisible group-hover/item:opacity-100 group-hover/item:visible transition-all duration-300 whitespace-nowrap z-50 translate-x-3 group-hover/item:translate-x-0 shadow-2xl shadow-black/20 pointer-events-none border border-white/10 uppercase tracking-widest">
            {item.label}
          </div>
        )}
      </li>
    );
  };

  const NavGroup = ({ label, items, className = "" }: { label: string, items: any[], className?: string }) => (
    <div className={`space-y-1.5 ${className}`}>
      {!isCollapsed && (
        <p className="text-[10px] font-extrabold text-gray-400 uppercase tracking-[0.2em] px-4 mb-2.5 opacity-80">{label}</p>
      )}
      <ul className="space-y-1">
        {items.map((item) => <NavItem key={item.href} item={item} />)}
      </ul>
    </div>
  );

  // Settings portal popup rendered directly into document.body
  const filterNav = (items: any[]) => {
    if (!user?.role) return [];

    // Normalize role for comparison
    const userRole = user.role.toLowerCase();

    // DEBUG: Log role to help identify mismatches if visibility issues persist
    console.log('[Sidebar] Current User Role:', userRole);

    // FAIL-SAFE: Admins see everything
    if (userRole === 'superadmin' || userRole === 'admin') {
      return items;
    }

    return items.filter((item) => 
      !item.roles || item.roles.map((r: string) => r.toLowerCase()).includes(userRole)
    );
  };

  const SettingsPortalPopup = () => {
    if (!isMounted || !isCollapsed || !isSettingsHovered || !popupRect) return null;

    return ReactDOM.createPortal(
      <div
        style={{ top: popupRect.top, left: popupRect.left, position: 'fixed', zIndex: 99999 }}
        className="py-2 px-2 bg-white border border-gray-100 rounded-2xl shadow-2xl shadow-indigo-600/10 min-w-[160px] gpu-smooth"
        onMouseEnter={() => setIsSettingsHovered(true)}
        onMouseLeave={() => setIsSettingsHovered(false)}
      >
        <div className="px-3 py-2 mb-1 border-b border-gray-50">
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Hệ thống</p>
        </div>
        <ul className="space-y-1">
          {filterNav(settingsChildren).map(child => {
            const isChildActive = pathname === child.href;
            const ChildIcon = child.icon;
            return (
              <li key={child.href}>
                <Link
                  href={child.href}
                  onClick={() => setIsSettingsHovered(false)}
                  className={`flex items-center gap-3 px-3 py-2 rounded-xl transition-all duration-200 group/sub ${
                    isChildActive
                      ? 'bg-indigo-50 text-indigo-700'
                      : 'text-gray-500 hover:bg-gray-50 hover:text-indigo-600'
                  }`}
                >
                  <div className={`w-7 h-7 rounded-lg flex items-center justify-center border transition-all ${
                    isChildActive ? 'bg-white border-indigo-100' : 'bg-gray-50 border-transparent group-hover/sub:bg-white group-hover/sub:border-indigo-100'
                  }`}>
                    <ChildIcon className={`w-3.5 h-3.5 ${isChildActive ? 'text-indigo-600' : 'text-gray-400 group-hover/sub:text-indigo-600'}`} />
                  </div>
                  <span className={`text-[11px] ${isChildActive ? 'font-bold' : 'font-semibold'}`}>{child.label}</span>
                </Link>
              </li>
            );
          })}
        </ul>
        {/* Pointer arrow */}
        <div className="absolute top-4 -left-1 w-2 h-2 bg-white rotate-45 border-l border-b border-gray-100" />
      </div>,
      document.body
    );
  };

  return (
    <motion.aside 
      className="gpu-smooth bg-white/80 backdrop-blur-xl border-r border-gray-100 flex flex-col h-screen w-full sticky top-0 overflow-visible transition-[background-color,border-color,box-shadow] duration-300 ease-[cubic-bezier(0.22,1,0.36,1)] shadow-xl shadow-gray-200/15 z-[100]"
    >

