        >
          <ChevronLeft className={`w-3.5 h-3.5 motion-safe-transition ${isCollapsed ? 'rotate-180' : ''}`} />
        </button>
      )}

      {/* Brand Header */}
      <div className={`h-20 shrink-0 relative overflow-hidden group border-b border-gray-100 flex items-center ${isCollapsed ? 'justify-center px-0' : 'px-6'}`}>
        {/* Animated background glow */}
        <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-indigo-500/16 to-purple-500/16 blur-[44px] -translate-y-1/2 translate-x-1/2 rounded-full group-hover:scale-110 motion-safe-transition pointer-events-none" />

        <div className="flex items-center gap-3 relative z-10">
          <div className={`${isCollapsed ? 'w-11 h-11' : 'w-10 h-10'} gpu-smooth bg-gradient-to-br from-indigo-600 via-indigo-700 to-indigo-900 rounded-2xl flex items-center justify-center shadow-xl shadow-indigo-600/25 group-hover:scale-[1.03] group-hover:-rotate-3 motion-safe-transition p-1 relative`}>
             <div className="w-full h-full border border-white/20 rounded-xl flex items-center justify-center relative overflow-hidden">
                <Navigation className="text-white w-5 h-5 rotate-45 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 motion-safe-transition" />
                <div className="absolute inset-0 bg-gradient-to-tr from-white/0 via-white/10 to-white/0 -translate-x-full group-hover:translate-x-full transition-transform duration-700" />
             </div>
             <div className="absolute -top-1 -right-1 w-3.5 h-3.5 bg-emerald-500 border-2 border-white rounded-full flex items-center justify-center animate-pulse">
                <Sparkles className="w-1.5 h-1.5 text-white" />
             </div>
          </div>

          {!isCollapsed && (
            <motion.div 
              initial={shouldReduceMotion ? false : { opacity: 0, x: -6 }}
              animate={{ opacity: 1, x: 0 }}
              exit={shouldReduceMotion ? undefined : { opacity: 0, x: -6 }}
              transition={shouldReduceMotion ? { duration: 0.12 } : { duration: 0.18, ease: [0.22, 1, 0.36, 1] }}
              className="flex flex-col"
            >
              <h1 className="font-black text-lg leading-none text-gray-900 tracking-tight uppercase group-hover:text-indigo-600 transition-colors">
                 QLHV <span className="text-indigo-600 group-hover:text-gray-900 transition-colors">ST</span>
              </h1>
              <p className="text-[7px] text-gray-400 font-black uppercase tracking-[0.3em] mt-1 opacity-60 flex items-center gap-1.5">
                 <span className="w-1 h-1 bg-emerald-500 rounded-full"></span>
                 Academy
              </p>
            </motion.div>
          )}
        </div>
      </div>

      {/* Navigation Scroll Area */}
      <nav className={`flex-1 ${isCollapsed ? 'px-2' : 'px-4'} py-6 ${isCollapsed ? 'overflow-visible' : 'overflow-y-auto'} hide-scrollbar space-y-6`}>

        <NavGroup label="Hệ thống" items={filterNav(overviewNav)} />
        <NavGroup label="Quản lý" items={filterNav(managementNav)} />
        <NavGroup label="Đào tạo & Sát hạch" items={filterNav(trainingNav)} />

        {/* Settings Block */}
        <div className="space-y-1.5">
          {!isCollapsed && (
            <p className="text-[10px] font-extrabold text-gray-400 uppercase tracking-[0.2em] px-4 mb-2.5 opacity-80">Hệ thống</p>
          )}

          <div 
            ref={settingsBtnRef}
            className="relative group/item"
            onMouseEnter={() => {
              if (isCollapsed) {
                const rect = settingsBtnRef.current?.getBoundingClientRect();
                if (rect) {
                  setPopupRect({ top: rect.top, left: rect.right + 12 });
                }
                setIsSettingsHovered(true);
              }
            }}
            onMouseLeave={() => {
              if (isCollapsed) {
                // Small delay to allow moving mouse to popup without it disappearing
                setTimeout(() => {
                  // Check if mouse is now over the portal popup - if not, hide
                  // We rely on the popup's own onMouseLeave to handle this
                }, 50);
              }
            }}
          >
            <button
              onClick={() => !isCollapsed && setSettingsOpen(o => !o)}
              className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl transition-all duration-300 group border ${
                isSettingsSection
                  ? 'bg-indigo-600/5 text-indigo-700 border-indigo-100/50'
                  : 'text-gray-500 hover:bg-gray-50 hover:text-gray-900 border-transparent'
              } ${isCollapsed ? 'justify-center px-0 w-12 h-12 mx-auto' : ''}`}
            >
              <Settings className={`w-5 h-5 shrink-0 transition-all duration-300 ${isSettingsSection ? 'text-indigo-600 scale-110' : 'text-gray-400 group-hover:text-gray-700 group-hover:scale-110'}`} />
              {!isCollapsed && (
                <>
                  <span className={`text-sm flex-1 text-left ${isSettingsSection ? 'font-bold' : 'font-semibold'}`}>Cài đặt</span>
                  {settingsOpen
                    ? <ChevronDown className={`w-3.5 h-3.5 transition-colors ${isSettingsSection ? 'text-indigo-600' : 'text-gray-400'}`} />
                    : <ChevronRight className={`w-3.5 h-3.5 transition-colors ${isSettingsSection ? 'text-indigo-600' : 'text-gray-400'}`} />}
                </>
              )}
            </button>

            {/* Tooltip for collapsed mode - only when popup not shown */}
            {isCollapsed && !isSettingsHovered && (
              <div className="absolute left-full ml-4 px-3 py-1.5 bg-gray-900/90 backdrop-blur-md text-white text-[10px] font-black rounded-xl opacity-0 invisible group-hover/item:opacity-100 group-hover/item:visible transition-all duration-300 whitespace-nowrap z-50 translate-x-3 group-hover/item:translate-x-0 shadow-2xl shadow-black/20 pointer-events-none border border-white/10 uppercase tracking-widest">
                Cài đặt
              </div>
            )}
          </div>

          {settingsOpen && (
            <ul className="mt-1 ml-4 pl-4 border-l-2 border-gray-100 space-y-1 animate-in slide-in-from-top-2 duration-300">
              {filterNav(settingsChildren).map(child => {
                const isChildActive = pathname === child.href;
                const ChildIcon = child.icon;
                return (
                  <li key={child.href}>
                    <Link
                      href={child.href}
                      className={`flex items-center gap-2.5 px-3 py-2 rounded-lg transition-all duration-150 text-xs group ${
                        isChildActive
                          ? 'bg-indigo-50 text-indigo-700 font-extrabold'
                          : 'text-gray-500 hover:text-indigo-600 font-semibold'
                      }`}
                    >
                      <ChildIcon className={`w-3.5 h-3.5 shrink-0 ${isChildActive ? 'text-indigo-600' : 'text-gray-400 group-hover:text-indigo-500'}`} />
                      {child.label}
                    </Link>
                  </li>
                );
              })}
            </ul>
          )}
        </div>
      </nav>

      {/* Logout Action */}
      <div className={`mt-auto p-4 border-t border-gray-50 bg-gray-50/10 flex flex-col items-center ${isCollapsed ? 'gap-4 pb-8' : 'gap-6 p-6'}`}>

        <button 
          onClick={() => setIsLogoutConfirmOpen(true)}
          className={`group flex items-center gap-3 px-4 py-2.5 rounded-xl transition-all duration-300 text-rose-500 hover:bg-rose-50 border border-transparent w-full ${isCollapsed ? 'justify-center px-0 w-12 h-12' : ''}`}
        >
          <LogOut className={`w-5 h-5 transition-transform duration-300 group-hover:rotate-12 ${isCollapsed ? 'scale-110' : ''}`} />
          {!isCollapsed && <span className="text-sm font-bold tracking-tight">Đăng xuất</span>}
        </button>

        {!isCollapsed && (
          <div className="flex flex-col items-center gap-1 opacity-20 hover:opacity-100 transition-all duration-500 cursor-default group/sig translate-y-2 hover:translate-y-0">
            <div className="flex items-center gap-1.5 grayscale group-hover/sig:grayscale-0 transition-all">
              <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest group-hover/sig:text-indigo-400">Crafted by</span>
              <div className="h-[1px] w-3 bg-gray-200 group-hover/sig:w-6 group-hover/sig:bg-indigo-200 transition-all duration-700"></div>
            </div>
            <div className="relative">
              <span className="text-[10px] font-black text-gray-900 tracking-tight uppercase flex items-center gap-1 group-hover/sig:text-indigo-700 transition-colors">
                Nịnh Thanh Khương
              </span>
              <div className="absolute -bottom-1 left-0 right-0 h-[2px] bg-indigo-600 scale-x-0 group-hover/sig:scale-x-100 transition-transform origin-left duration-500" />
            </div>
          </div>
        )}
      </div>

      <ConfirmModal 
        isOpen={isLogoutConfirmOpen}
        onClose={() => setIsLogoutConfirmOpen(false)}
        onConfirm={() => {
          setIsLogoutConfirmOpen(false);
          setToken(null);
          toast.success('Đã đăng xuất thành công');
          router.push('/login');
        }}
        title="Đăng xuất hệ thống"
        message="Bạn có chắc chắn muốn thoát khỏi phiên làm việc hiện tại không?"
        confirmText="Đăng xuất"
        type="danger"
      />

      {/* Settings Popup Portal - renders directly into document.body to escape all stacking contexts */}
      <SettingsPortalPopup />
    </motion.aside>
  );
};

export default Sidebar;

'use client';

import React, { useMemo, useState } from 'react';
import {
  Search,
  Bell,
  Settings as SettingsIcon,
  ChevronDown,
  LogOut,
  User,
  HelpCircle,
  LayoutDashboard,
  Users,
  GraduationCap,
  Car,
  Calendar,
  BarChart3,
  ClipboardList,
