  { label: 'Lịch học', href: '/schedules', icon: Calendar, category: 'Training' },
  { label: 'Tiến độ (DAT)', href: '/progress', icon: BarChart3, category: 'Training' },
  { label: 'Thi tốt nghiệp', href: '/graduation-exam', icon: GraduationCap, category: 'Exam' },
  { label: 'Thi sát hạch', href: '/sat-hach', icon: ClipboardList, category: 'Exam' },
  { label: 'Học phí', href: '/tuition', icon: CreditCard, category: 'Finance' },
  { label: 'Cài đặt tài khoản', href: '/profile', icon: User, category: 'Settings' },
  { label: 'Cài đặt hệ thống', href: '/settings', icon: SettingsIcon, category: 'Settings' },
  { label: 'Thông báo', href: '/settings/notifications', icon: Bell, category: 'Settings' },
  { label: 'Bảo mật', href: '/settings/security', icon: Shield, category: 'Settings' },
