];

interface TopbarProps {
  onToggleSidebar?: () => void;
}

const Topbar: React.FC<TopbarProps> = ({ onToggleSidebar }) => {
  const router = useRouter();
  const { setToken, user } = useAuth();
  const shouldReduceMotion = useReducedMotion();
  const [showNotifications, setShowNotifications] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const [dashboardStats, setDashboardStats] = useState<any>(null);

  React.useEffect(() => {
    let isMounted = true;

    const fetchStats = async () => {
      try {
        const res = await getDashboardStats();
        if (isMounted && res.success) {
          setDashboardStats(res.data);
        }
      } catch {
        // Keep topbar silent on background sync failures for smoother UX
      }
    };

    fetchStats();
    const interval = window.setInterval(fetchStats, 60000);

    return () => {
      isMounted = false;
      window.clearInterval(interval);
    };
  }, []);

  const handleMarkAllAsRead = async () => {
    if (!user?.id) return;
    try {
      await markAllNotificationsAsRead(user.id);
      // Refresh stats to clear the bubble
      const res = await getDashboardStats();
      if (res.success) {
        setDashboardStats(res.data);
      }
      toast.success('Đã đánh dấu tất cả là đã đọc');
    } catch (error) {
      console.error('Failed to mark notifications as read:', error);
      toast.error('Có lỗi xảy ra khi cập nhật thông báo');
    }
  };

  // Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearchFocused, setIsSearchFocused] = useState(false);
  const searchInputRef = React.useRef<HTMLInputElement>(null);

  const filteredNav = useMemo(() => {
    const normalizedQuery = searchQuery.trim().toLowerCase();
    if (!normalizedQuery) return [];

    return NAV_INDEX.filter(
      (item) =>
        item.label.toLowerCase().includes(normalizedQuery) || item.category.toLowerCase().includes(normalizedQuery),
    ).slice(0, 5);
  }, [searchQuery]);

  // Ctrl+K Shortcut
  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        searchInputRef.current?.focus();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleSettings = () => router.push('/settings');
  const handleProfile = () => router.push('/profile');
  const handleHelp = () => router.push('/help');
  const handleLogout = () => {
    setShowLogoutConfirm(true);
    setShowProfileMenu(false);
  };

  const confirmLogout = () => {
    setToken(null);
    toast.success('Đã đăng xuất thành công');
    router.push('/login');
  };

  return (
    <header className="gpu-smooth h-20 bg-white/80 backdrop-blur-md border-b border-gray-100 flex items-center justify-between px-4 sm:px-8 sticky top-0 z-30 transition-colors duration-200">
      {/* Mobile sidebar toggle */}
      <button
        onClick={onToggleSidebar}
        className="p-2 rounded-xl text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 transition-all lg:hidden mr-2 shrink-0"
        aria-label="Toggle sidebar"
      >
        <PanelLeft className="w-5 h-5" />
      </button>

      <ConfirmModal
        isOpen={showLogoutConfirm}
        onClose={() => setShowLogoutConfirm(false)}
        onConfirm={confirmLogout}
        title="Đăng xuất tài khoản"
        message="Bạn có chắc chắn muốn thoát khỏi hệ thống quản lý ngay bây giờ?"
        type="danger"
        confirmText="Đăng xuất"
      />
      {/* Search Section */}
      <div className="flex-1 max-w-md relative">
        <div
          className={`relative group transition-all duration-300 ${isSearchFocused ? 'ring-4 ring-primary/10 rounded-2xl' : ''}`}
        >
          <Search
            className={`absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 transition-colors ${isSearchFocused ? 'text-primary' : 'text-gray-400 group-hover:text-primary/70'}`}
          />
          <input
            ref={searchInputRef}
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onFocus={() => setIsSearchFocused(true)}
            onBlur={() => {
              // Delay hiding to allow clicks on dropdown items
              setTimeout(() => setIsSearchFocused(false), 200);
            }}
            placeholder="Tìm kiếm trang đích... (Ctrl+K)"
            className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-transparent focus:border-primary/20 focus:bg-white outline-none rounded-2xl text-sm font-medium transition-all shadow-sm focus:shadow-md"
          />
        </div>

        {/* Search Results Dropdown */}
        <AnimatePresence>
          {isSearchFocused && searchQuery.trim() !== '' && (
            <motion.div
              initial={shouldReduceMotion ? false : { opacity: 0, y: 6, scale: 0.985 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={shouldReduceMotion ? undefined : { opacity: 0, y: 4, scale: 0.99 }}
              transition={shouldReduceMotion ? { duration: 0.12 } : { duration: 0.18, ease: [0.22, 1, 0.36, 1] }}
              className="absolute top-full left-0 right-0 mt-2 bg-white border border-gray-100 rounded-2xl shadow-xl z-20 overflow-hidden gpu-smooth"
            >
              <div className="py-2">
