                >
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-xl bg-indigo-600 flex items-center justify-center border border-indigo-500 shadow-sm shadow-indigo-600/20">
                      <Users className="w-4 h-4 text-white" />
