React.useEffect(() => {
  let cancelled = false;
  const fetchThreshold = async () => {
    try {
      const res = await getSystemSettings();
      if (!cancelled && res.success && res.data && res.data.practiceTargetMinutes) {
        setGlobalTargetMin(res.data.practiceTargetMinutes);
      }
    } catch (e) {
      if (!cancelled) console.error('Lỗi tải cấu hình ngưỡng:', e);
    }
  };

  const fetchStudents = async () => {
    setIsLoading(true);
    try {
      const res = await getStudents(1, 100, { vehicle_type: 'Ô tô' });
      if (cancelled) return;
      if (res.success && res.data && res.data.data) {
        const studentList = Array.isArray(res.data.data) ? res.data.data : [];
        const mapped: PracticeStudent[] = studentList.map((s: any) => {
          const stats = s.practice_stats || { session_count: 0, total_minutes: 0, last_session: null };
          const totalMin = stats.total_minutes || 0;

          return {
            id: s._id,
            student_id: s.user_id?._id || '',
            name: s.user_id?.first_name ? `${s.user_id.last_name || ''} ${s.user_id.first_name}`.trim() : 'Chưa có tên',
            phone: s.user_id?.phone || 'Chưa cập nhật',
            rank: s.license_category_name || s.license_category_id || 'B2',
            region: s.region_id?.name || 'Chưa phân bổ',
            sessions: stats.session_count || 0,
            totalMin: totalMin,
            targetMin: globalTargetMin,
            lastSession: stats.last_session
              ? (() => {
                  const ls = stats.last_session;
                  const date = ls.start_time ? new Date(ls.start_time).toLocaleDateString('vi-VN') : '';
                  const mins = parseFloat(ls.hour) || 0;
                  const duration = mins >= 60 ? `${Math.round((mins / 60) * 10) / 10}h` : `${mins} phút`;
                  return `${date} (${duration})`;
                })()
              : 'Chưa có',
            status: (() => {
              const mins = totalMin;
              const target = globalTargetMin;
              if (mins === 0) return 'pending';
              if (mins < target) return 'in-progress';
              return 'done';
            })(),
          };
        });
        setStudents(mapped);
        setStudentsData(mapped);
      }
    } catch (error) {
      if (!cancelled) {
        console.error('Lỗi tải danh sách học viên:', error);
      }
    } finally {
      if (!cancelled) setIsLoading(false);
    }
  };

  fetchThreshold();
  fetchStudents();
  return () => { cancelled = true; };
}, [globalTargetMin]);

